body:
"""Lazy-init Supabase client. Raises a clear error if env vars are missing."""
global _client
if _client is None:
    if not SUPABASE_URL or not SUPABASE_KEY:
        raise RuntimeError(
            "Supabase is not configured. Set SUPABASE_URL and SUPABASE_SECRET_KEY."
        )
    _client = create_client(SUPABASE_URL, SUPABASE_KEY)
return _client

"""Idempotent: returns the user, creating one if it doesn't exist yet."""
existing = get_user_by_email(email)
if existing:
    return existing
res = get_client().table("users").insert({
    "email": email.lower(),
    "plan": plan,
}).execute()
return (res.data or [])[0]

patch: dict[str, Any] = {"plan": plan}
if status is not None:
    patch["subscription_status"] = status
if period_end is not None:
    patch["current_period_end"] = period_end.isoformat()
if stripe_customer_id is not None:
    patch["stripe_customer_id"] = stripe_customer_id
get_client().table("users").update(patch).eq("id", user_id).execute()

payload: dict[str, Any] = {
    "user_id": user_id,
    "token_hash": token_hash,
    "token_prefix": token_prefix,
}
if expires_at is not None:
    payload["expires_at"] = expires_at.isoformat()
if name is not None:
    payload["name"] = name
res = get_client().table("tokens").insert(payload).execute()
return (res.data or [])[0]

get_client().table("tokens").update({
    "last_used_at": now_utc().isoformat(),
}).eq("token_hash", token_hash).execute()

get_client().table("tokens").update({
    "revoked_at": now_utc().isoformat(),
}).eq("token_hash", token_hash).execute()

get_client().table("device_codes").update({
    "status": "authorized",
    "user_id": user_id,
    "authorized_at": now_utc().isoformat(),
}).eq("device_code", device_code).execute()

get_client().table("device_codes").update({
    "last_polled_at": now_utc().isoformat(),
}).eq("device_code", device_code).execute()

get_client().table("device_codes").update({
    "status": "expired",
}).eq("device_code", device_code).execute()

try:
    get_client().table("webhook_events").insert({
        "event_id": event_id,
        "event_type": event_type,
        "payload": payload,
    }).execute()
except Exception as e:
    # Race: another worker recorded it first. That's fine — webhook is idempotent.
    logger.info(f"Webhook {event_id} already recorded by another worker: {e}")

"""Reverse a consume — used when a scan that consumed a credit fails."""
try:
    res = get_client().rpc(
        "refund_scan_credit",
        {"p_credit_id": credit_id},
    ).execute()
    return bool(res.data)
except Exception as e:
    logger.warning(f"refund_scan_credit({credit_id}) failed: {e}")
    return False

"""Read-only: how many unused credits this user has."""
try:
    res = get_client().rpc(
        "available_scan_credits",
        {"p_user_id": user_id},
    ).execute()
    return int(res.data or 0)
except Exception as e:
    logger.warning(f"available_scan_credits({user_id}) failed: {e}")
    return 0

if request.method in ("POST", "PUT"):
    content_length = request.headers.get("content-length")
    # /v1/scans/log and /v1/scans/{id}/report store large blobs
    path = request.url.path
    # Scan logs + reports carry large blobs. Real-world ceilings:
    #   - Mid-size repos (~500 files): 1-3MB
    #   - Large repos (~3500 files, e.g. shadcn-ui/ui): 10-15MB
    #   - Monorepos (10k+ files): 25-50MB
    # The CLI applies progressive trimming client-side targeting
    # 9MB; this server cap is the hard backstop for legit huge
    # uploads after trimming. Was 10MB pre-2026-04-29 — raised
    # after a shadcn-ui scan was rejected with HTTP 413.
    # /v1/analyze payloads can be 30-100KB (30 functions × 60 lines).
    # Everything else stays at 50KB.
    if "/scans/log" in path or "/report" in path:
        limit_bytes = 25 * 1024 * 1024
    elif "/analyze" in path or "/scan" in path or "/fix-prompts" in path or "/embed" in path or "/coherence" in path:
        limit_bytes = 200 * 1024  # 200KB for ML analysis + fix-prompt + embed + coherence payloads
    else:
        limit_bytes = 50 * 1024
    if content_length and int(content_length) > limit_bytes:
        return JSONResponse(
            {
                "detail": (
                    f"Request body too large "
                    f"({int(content_length) // 1024}KB > max {limit_bytes // 1024}KB). "
                    f"Update to the latest CLI which trims large result_json "
                    f"automatically before upload."
                )
            },
            status_code=413,
        )
return await call_next(request)

# Honor Fly-Client-IP / X-Forwarded-For when behind the proxy
fly = request.headers.get("Fly-Client-IP")
if fly:
    return fly
fwd = request.headers.get("X-Forwarded-For")
if fwd:
    return fwd.split(",")[0].strip()
return request.client.host if request.client else "unknown"

"""
Classify a single deviation.

Returns: {
  "file": str,
  "verdict": "justified" | "accidental",
  "confidence": float (0-1),
  "needs_llm": bool,
  "method": "ml_model" | "rule_based"
}
"""
features = self.extract_features(deviation)

if self.is_loaded and self.model is not None:
    try:
        return self._classify_with_model(deviation, features)
    except Exception as e:
        import logging
        logging.getLogger(__name__).warning(f"ML model failed, falling back to rules: {e}")
        return self._classify_with_rules(deviation, features)
else:
    return self._classify_with_rules(deviation, features)

dot = np.dot(a, b)
norm_a = np.linalg.norm(a)
norm_b = np.linalg.norm(b)
if norm_a == 0 or norm_b == 0:
    return 0.0
return float(dot / (norm_a * norm_b))

"""
Return the (start, end) of the current billing period.

For paid users we use users.current_period_end if present (set by
the Stripe webhook). For free users we use a calendar month rooted
at the user's signup day-of-month.
"""
now = datetime.now(timezone.utc)
period_end_str = user_row.get("current_period_end")

if period_end_str:
    try:
        end = datetime.fromisoformat(period_end_str.replace("Z", "+00:00"))
        start = end - timedelta(days=30)
        return start, end
    except Exception:
        pass

# Free / no Stripe period — calendar month
start = datetime(now.year, now.month, 1, tzinfo=timezone.utc)
if now.month == 12:
    end = datetime(now.year + 1, 1, 1, tzinfo=timezone.utc)
else:
    end = datetime(now.year, now.month + 1, 1, tzinfo=timezone.utc)
return start, end

auth = await require_authenticated(request)
user_id = auth["user_id"]

user = db.get_user_by_id(user_id)
if not user:
    raise HTTPException(status_code=404, detail="User not found")

customer_id = user.get("stripe_customer_id")
if not customer_id:
    # User has no Stripe customer yet — create one on the fly so the portal works.
    try:
        customer_id = find_or_create_customer(user["email"])
        db.update_user_plan(
            user_id=user_id,
            plan=user.get("plan", "free"),
            stripe_customer_id=customer_id,
        )
    except Exception as e:
        logger.error(f"Could not create Stripe customer: {e}")
        raise HTTPException(
            status_code=402,
            detail="No billing account exists. Run `vibedrift upgrade` to start a paid plan.",
        )

try:
    url = create_portal_session(customer_id)
except Exception as e:
    logger.error(f"Stripe portal session failed: {e}")
    raise HTTPException(status_code=502, detail="Could not create billing portal session")

return PortalResponse(url=url)

if not authorization or not authorization.lower().startswith("bearer "):
    raise HTTPException(status_code=401, detail="Missing or malformed Authorization header")
return authorization[7:].strip()

"""
CLI poll. Returns the current status of the device_code:
  - pending:    keep polling
  - authorized: returns access_token + user info (one-shot — token issued here)
  - expired:    code TTL elapsed, CLI must restart
  - denied:     user explicitly denied (currently never set; reserved for future)
"""
row = db.get_device_code_by_device(body.device_code)
if row is None:
    # Unknown / stale device_code — treat as expired so the CLI restarts
    return DevicePollResponse(status="expired", message="Unknown device_code")

db.mark_device_code_polled(body.device_code)

# Has it expired by wallclock?
from datetime import datetime, timezone
expires_at = row.get("expires_at")
if expires_at:
    try:
        exp = datetime.fromisoformat(expires_at.replace("Z", "+00:00"))
        if exp < datetime.now(timezone.utc):
            db.expire_device_code(body.device_code)
            return DevicePollResponse(status="expired")
    except Exception:
        pass

status = row.get("status", "pending")
if status == "pending":
    return DevicePollResponse(status="pending")
if status == "denied":
    return DevicePollResponse(status="denied")
if status == "expired":
    return DevicePollResponse(status="expired")

if status == "authorized":
    user_id = row.get("user_id")
    if not user_id:
        # Defensive: if status is authorized but user_id missing, treat as expired
        db.expire_device_code(body.device_code)
        return DevicePollResponse(status="expired")

    user = db.get_user_by_id(user_id)
    if not user:
        db.expire_device_code(body.device_code)
        return DevicePollResponse(status="expired")

    # Issue a fresh token (single-use device flow — never reuse)
    raw, token_hash, prefix = db.generate_token()
    expires_at_dt = db.now_utc() + timedelta(days=TOKEN_TTL_DAYS)
    db.insert_token(
        user_id=user_id,
        token_hash=token_hash,
        token_prefix=prefix,
        expires_at=expires_at_dt,
        name="cli",
    )

    # One-shot — mark this device_code as expired so polling can never re-issue
    db.expire_device_code(body.device_code)

    return DevicePollResponse(
        status="authorized",
        access_token=raw,
        email=user["email"],
        plan=user.get("plan", "free"),
        expires_at=expires_at_dt.isoformat(),
    )

return DevicePollResponse(status="pending")

if not isinstance(raw, dict):
    return None
title = str(raw.get("title", "")).strip()
if not title:
    return None
locs = raw.get("locations") or []
if isinstance(locs, str):
    locs = [locs]
locations = [str(x) for x in locs if str(x).strip()][:10]
sev = str(raw.get("severity", "medium")).lower().strip()
if sev not in {"critical", "high", "medium", "low"}:
    sev = "medium"
try:
    rank = int(raw.get("rank", fallback_rank))
except (TypeError, ValueError):
    rank = fallback_rank
return RankedIssue(
    rank=rank,
    title=title[:200],
    severity=sev,
    pattern=str(raw.get("pattern", ""))[:200],
    locations=locations,
    why=str(raw.get("why", ""))[:600],
    fix=str(raw.get("fix", ""))[:1200],
)

cleaned = (text or "").strip()
if cleaned.startswith("```"):
    cleaned = cleaned.replace("```json", "").replace("```", "").strip()
parsed: dict = {}
try:
    parsed = json.loads(cleaned)
except json.JSONDecodeError:
    match = re.search(r"\{[\s\S]*\}", cleaned)
    if match:
        try:
            parsed = json.loads(match.group())
        except json.JSONDecodeError:
            parsed = {}
if not isinstance(parsed, dict):
    return CoherenceReport()

issues_raw = parsed.get("ranked_issues") or []
issues: List[RankedIssue] = []
if isinstance(issues_raw, list):
    for i, r in enumerate(issues_raw):
        issue = _coerce_issue(r, i + 1)
        if issue:
            issues.append(issue)
issues.sort(key=lambda x: x.rank)

strengths_raw = parsed.get("strengths") or []
strengths = [str(s)[:240] for s in strengths_raw if str(s).strip()][:5] if isinstance(strengths_raw, list) else []

try:
    score = int(parsed.get("coherence_score", 0))
except (TypeError, ValueError):
    score = 0
score = max(0, min(100, score))

return CoherenceReport(
    coherence_grade=str(parsed.get("coherence_grade", ""))[:2],
    coherence_score=score,
    verdict=str(parsed.get("verdict", ""))[:600],
    ranked_issues=issues,
    strengths=strengths,
)

start = time.time()

auth = await require_authenticated(request)
user_id: Optional[str] = auth.get("user_id")

if len(body.functions) > MAX_FUNCTIONS_PER_EMBED:
    raise HTTPException(
        status_code=400,
        detail=f"Max {MAX_FUNCTIONS_PER_EMBED} functions per embed request",
    )

# Runaway guard (not a paywall).
if user_id:
    ok, _remaining, reset_s = _check_hourly_rate_limit(f"embed:{user_id}", EMBED_HOURLY_CAP)
    if not ok:
        raise HTTPException(
            status_code=429,
            detail={"error": "rate_limited", "retry_after_seconds": reset_s},
        )

engine = getattr(request.app.state, "embedding_engine", None)
models_ready = getattr(request.app.state, "models_ready", False)
if not models_ready or engine is None or not engine.is_loaded:
    raise HTTPException(status_code=503, detail="Models still loading, try again shortly")

items: list[EmbeddingItem] = []
if body.functions:
    # Truncate to the same line cap /v1/analyze uses, so a function embeds
    # identically whether it arrives here or through the full deep scan.
    bodies: list[str] = []
    for fn in body.functions:
        lines = fn.body.split("\n")
        bodies.append(
            "\n".join(lines[:MAX_LINES_PER_FUNCTION]) if len(lines) > MAX_LINES_PER_FUNCTION else fn.body
        )
    vectors = engine.embed_batch(bodies)
    if vectors is not None and len(vectors) == len(body.functions):
        for fn, vec in zip(body.functions, vectors):
            items.append(EmbeddingItem(id=fn.id, vector=[float(x) for x in vec.tolist()]))

elapsed_ms = int((time.time() - start) * 1000)
logger.info(
    f"Embedded {len(items)} functions (source={body.source}) user={user_id} — {elapsed_ms}ms"
)
return EmbedResponse(
    model=MODEL_NAME,
    dim=int(getattr(engine, "embedding_dim", 768)),
    embeddings=items,
    processing_time_ms=elapsed_ms,
)

"""
Collect user feedback on ML findings for training data.
Writes to the `feedback` table (migration 002_training.sql).
Auth is optional — anonymous votes are accepted.
"""
user_id: Optional[str] = None
try:
    auth = await resolve_auth_optional(request)
    if auth:
        user_id = auth.get("user_id")
except Exception:
    pass

try:
    client = db.get_client()
    client.table("feedback").delete().eq(
        "finding_hash", body.finding_hash
    ).execute()
    client.table("feedback").insert({
        "scan_id": body.scan_id,
        "finding_type": body.finding_type,
        "finding_hash": body.finding_hash,
        "user_id": user_id,
        "vote": body.vote,
    }).execute()
except Exception as e:
    logger.error(f"Failed to insert ML feedback: {e}")
    # Still return success — client shouldn't retry votes

return {"status": "received", "finding_hash": body.finding_hash}

"""
Free-form feedback from CLI / dashboard / landing.

Anonymous submissions are allowed — we still want to hear from
users who haven't signed up. When the bearer token IS present we
attach the user_id + email so triage can follow up directly.
"""
# Validate source
if body.source not in {"cli", "dashboard", "landing"}:
    raise HTTPException(
        status_code=400,
        detail="source must be one of: cli, dashboard, landing",
    )

# Cap message length on the server too — never trust the client
msg = body.message.strip()
if not msg:
    raise HTTPException(status_code=400, detail="message cannot be empty")
if len(msg.encode("utf-8")) > MAX_MESSAGE_BYTES:
    raise HTTPException(
        status_code=400,
        detail=f"message too long (max {MAX_MESSAGE_BYTES} bytes)",
    )

# Best-effort auth resolution: token is optional but we use it
# when available so triage knows who to talk to.
user_id: Optional[str] = None
email: Optional[str] = body.email
try:
    auth = await resolve_auth_optional(request)
    if auth:
        user_id = auth.get("user_id")
        if not email:
            email = auth.get("email")
except Exception as e:
    logger.info(f"feedback: optional auth resolve skipped: {e}")

metadata = body.metadata or {}
# Strip any sensitive-looking keys the client might have sent
metadata = {k: v for k, v in metadata.items() if k.lower() not in {"token", "password", "api_key", "secret"}}

try:
    res = (
        db.get_client()
        .table("user_feedback")
        .insert({
            "user_id": user_id,
            "email": email,
            "source": body.source,
            "message": msg,
            "metadata": metadata,
        })
        .execute()
    )
    rows = res.data or []
    if not rows:
        raise RuntimeError("insert returned no rows")
    row = rows[0]
except Exception as e:
    logger.error(f"Failed to insert user_feedback: {e}")
    raise HTTPException(status_code=503, detail="Could not record feedback")

logger.info(
    f"user_feedback {row['id']} from source={body.source} "
    f"user={user_id or 'anon'} ({len(msg)} chars)"
)
return GeneralFeedbackResponse(id=str(row["id"]), received_at=row["created_at"])

cleaned = text.strip()
if cleaned.startswith("```"):
    cleaned = cleaned.replace("```json", "").replace("```", "").strip()
try:
    parsed = json.loads(cleaned)
except json.JSONDecodeError:
    match = re.search(r"\{[\s\S]*\}", cleaned)
    if not match:
        return {}
    try:
        parsed = json.loads(match.group())
    except json.JSONDecodeError:
        return {}
prompts = parsed.get("prompts")
if not isinstance(prompts, dict):
    return {}
return {str(k): str(v) for k, v in prompts.items() if isinstance(v, str)}

auth = await require_authenticated(request)
user_id: Optional[str] = auth.get("user_id")
if not user_id:
    raise HTTPException(status_code=401, detail="authentication required")

# Ownership check — look up the scan by id and confirm it belongs to the caller
try:
    res = (
        db.get_client()
        .table("scans")
        .select("id,user_id")
        .eq("id", scan_id)
        .limit(1)
        .execute()
    )
except Exception as e:
    logger.error(f"upload_report lookup failed: {e}")
    raise HTTPException(status_code=500, detail="database error")

rows = res.data or []
if not rows:
    raise HTTPException(status_code=404, detail="scan not found")
if rows[0].get("user_id") != user_id:
    raise HTTPException(status_code=403, detail="not your scan")

html = body.report_html
size = len(html.encode("utf-8"))
if size == 0:
    raise HTTPException(status_code=400, detail="report_html is empty")
if size > MAX_REPORT_SIZE_BYTES:
    raise HTTPException(
        status_code=413,
        detail=f"report exceeds {MAX_REPORT_SIZE_BYTES // 1024}KB limit ({size // 1024}KB)",
    )

try:
    db.get_client().table("scans").update({"report_html": html}).eq(
        "id", scan_id
    ).execute()
except Exception as e:
    logger.error(f"upload_report write failed: {e}")
    raise HTTPException(status_code=500, detail="could not save report")

logger.info(
    f"Stored report for scan={scan_id} user={user_id} size={size} bytes"
)
return UploadReportResponse(ok=True, scan_id=scan_id, bytes=size)

auth = await require_authenticated(request)
user_id: Optional[str] = auth.get("user_id")
if not user_id:
    raise HTTPException(status_code=401, detail="authentication required")

try:
    res = (
        db.get_client()
        .table("scans")
        .select("user_id,report_html")
        .eq("id", scan_id)
        .limit(1)
        .execute()
    )
except Exception as e:
    logger.error(f"get_report lookup failed: {e}")
    raise HTTPException(status_code=500, detail="database error")

rows = res.data or []
if not rows:
    raise HTTPException(status_code=404, detail="scan not found")
row = rows[0]
if row.get("user_id") != user_id:
    raise HTTPException(status_code=403, detail="not your scan")
if not row.get("report_html"):
    raise HTTPException(status_code=404, detail="no report uploaded for this scan")

return Response(
    content=row["report_html"],
    media_type="text/html; charset=utf-8",
    headers={"Cache-Control": "private, max-age=300"},
)

payload = await request.body()
sig_header = request.headers.get("Stripe-Signature", "")

try:
    event = parse_webhook_event(payload, sig_header)
except ValueError as e:
    logger.warning(f"Webhook payload parse failed: {e}")
    raise HTTPException(status_code=400, detail="Invalid payload")
except Exception as e:
    # Distinguish actual signature failures from misconfiguration / SDK
    # errors so the logs aren't misleading. SignatureVerificationError
    # lives at stripe.error.SignatureVerificationError.
    try:
        from stripe.error import SignatureVerificationError  # type: ignore
    except Exception:
        SignatureVerificationError = ()  # type: ignore
    if SignatureVerificationError and isinstance(e, SignatureVerificationError):
        logger.warning(f"Webhook signature verification failed: {e}")
        raise HTTPException(status_code=400, detail="Invalid signature")
    logger.error(f"Webhook validation error (not a signature failure): {e}")
    raise HTTPException(status_code=400, detail="Webhook validation failed")

event_id = event["id"]
event_type = event["type"]

# Idempotency check
try:
    if db.webhook_already_processed(event_id):
        logger.info(f"Webhook {event_id} already processed, skipping")
        return {"received": True, "duplicate": True}
except Exception as e:
    # If the dedup table is unreachable, fall through and let the handler run.
    # Stripe will retry on transient failures, but the handlers themselves are
    # idempotent (upsert by stripe_subscription_id).
    logger.warning(f"Idempotency check failed (continuing): {e}")

handler = _HANDLERS.get(event_type)
handler_succeeded = True
if handler is None:
    logger.info(f"Webhook {event_type} ignored (no handler)")
else:
    try:
        handler(event["data"]["object"])
    except Exception as e:
        logger.error(f"Handler for {event_type} failed: {e}")
        handler_succeeded = False

# Only record as processed when the handler succeeded. If it failed,
# Stripe will retry (up to 3 days) and the handler gets another chance.
# Events with no handler are always recorded (nothing to retry).
if handler_succeeded:
    try:
        db.record_webhook_processed(event_id, event_type, event)
    except Exception as e:
        logger.warning(f"Could not record webhook event: {e}")

if not handler_succeeded:
    # Return 500 so Stripe knows to retry
    raise HTTPException(status_code=500, detail=f"Handler for {event_type} failed")

return {"received": True}

if self._client is None:
    if not ANTHROPIC_API_KEY:
        raise RuntimeError("ANTHROPIC_API_KEY is not configured")
    from anthropic import Anthropic
    self._client = Anthropic(api_key=ANTHROPIC_API_KEY)
return self._client

"""
Validate a list of medium-confidence ML findings.

Each input dict must have: id (any), question (str), snippet_a (str),
snippet_b (str), confidence (float).

Returns one result per input with: id, verdict (confirmed|rejected|uncertain),
explanation (<=200 chars), severity (info|warning|error).
"""
if not findings:
    return []

client = self._ensure()

# Build a single batched prompt — one Claude call per scan, not per finding.
items = []
for i, f in enumerate(findings):
    items.append(
        f"FINDING #{i + 1} (confidence {f.get('confidence', 0):.2f})\n"
        f"Question: {f.get('question', '')}\n"
        f"Snippet A:\n```\n{(f.get('snippet_a') or '')[:600]}\n```\n"
        f"Snippet B:\n```\n{(f.get('snippet_b') or '')[:600]}\n```\n"
    )

prompt = (
    "You are a senior code reviewer validating findings from an automated "
    "ML code analyzer. For each finding, decide whether it is CONFIRMED, "
    "REJECTED, or UNCERTAIN, and write a single sentence (≤25 words) explaining why.\n\n"
    "Respond ONLY in this JSON shape, no prose, no markdown fences:\n"
    '{"results":[{"id":1,"verdict":"confirmed","explanation":"...","severity":"warning"}, ...]}\n\n'
    "Severity rules: confirmed security issues = error; confirmed style/dup issues = warning; "
    "rejected/uncertain = info.\n\n"
    f"FINDINGS ({len(findings)}):\n\n" + "\n---\n".join(items)
)

try:
    response = client.messages.create(
        model=MODEL,
        max_tokens=MAX_VALIDATION_TOKENS,
        messages=[{"role": "user", "content": prompt}],
    )
except Exception as e:
    logger.error(f"Anthropic call failed: {e}")
    # Return uncertain for everything on failure
    return [
        {
            "id": i + 1,
            "verdict": "uncertain",
            "explanation": f"AI validation unavailable: {str(e)[:100]}",
            "severity": "info",
        }
        for i in range(len(findings))
    ]

text = response.content[0].text.strip()
if text.startswith("```"):
    text = re.sub(r"^```(?:json)?\s*", "", text)
    text = re.sub(r"\s*```$", "", text)

try:
    parsed = json.loads(text)
except json.JSONDecodeError:
    match = re.search(r"\{[\s\S]*\}", text)
    if match:
        try:
            parsed = json.loads(match.group())
        except Exception:
            parsed = {"results": []}
    else:
        parsed = {"results": []}

results = parsed.get("results") or []
# Normalize: pad missing entries with uncertain.
out: list[dict[str, Any]] = []
for i in range(len(findings)):
    if i < len(results) and isinstance(results[i], dict):
        r = results[i]
        out.append({
            "id": i + 1,
            "verdict": str(r.get("verdict", "uncertain")).lower(),
            "explanation": str(r.get("explanation", ""))[:240],
            "severity": str(r.get("severity", "info")).lower(),
        })
    else:
        out.append({
            "id": i + 1,
            "verdict": "uncertain",
            "explanation": "Validation produced no result for this finding",
            "severity": "info",
        })
return out

if ts is None:
    return None
return datetime.fromtimestamp(ts, tz=timezone.utc)

