"""Resolve {duplicate_high, duplicate_med, intent, struct_high, cos_med} for a language:
per-language entry, else _global, else hardcoded DEFAULTS. Unknown keys ignored;
missing keys fall back to DEFAULTS individually.

Back-compat (v1 files):
- If the file lacks 'cos_med' but has 'duplicate_med', use 'duplicate_med' for 'cos_med'.
- If the file lacks 'struct_high', use DEFAULTS['struct_high'] (0.95).
Never raises.
"""
langs = (loaded or {}).get("languages", {}) or {}
src = langs.get((language or "").lower()) or langs.get("_global") or {}
out = dict(DEFAULTS)
for k in DEFAULTS:
    if k in src:
        try:
            out[k] = float(src[k])
        except (TypeError, ValueError):
            pass
# Back-compat: v1 file has duplicate_med but not cos_med
if "cos_med" not in src and "duplicate_med" in src:
    try:
        out["cos_med"] = float(src["duplicate_med"])
    except (TypeError, ValueError):
        pass
# struct_high falls back to DEFAULTS if absent (already handled above via DEFAULTS seed)
return out
